#!/bin/bash\n\n# PlayStore Assets Helper Script\n# Usage: ./playstore-assets-helper.sh [generate|screenshots|submit|status]\n\nset -e\n\nSCRIPT_DIR=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)\"\nPROJECT_ROOT=\"$(cd \"$SCRIPT_DIR/../..\" && pwd)\"\n\necho \"🎮 Definition Detective - PlayStore Assets Helper\"\necho \"=================================================\"\necho \"\"\n\n# Colors\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nRED='\\033[0;31m'\nNC='\\033[0m' # No Color\n\nfunction print_step() {\n    echo -e \"${GREEN}✓${NC} $1\"\n}\n\nfunction print_warning() {\n    echo -e \"${YELLOW}⚠${NC} $1\"\n}\n\nfunction print_error() {\n    echo -e \"${RED}✗${NC} $1\"\n}\n\nfunction generate_assets() {\n    echo \"Generating PlayStore assets...\"\n    echo \"\"\n    \n    cd \"$SCRIPT_DIR\"\n    \n    # Check Python\n    if ! command -v python3 &> /dev/null; then\n        print_error \"Python3 not found\"\n        exit 1\n    fi\n    \n    # Check Pillow\n    if ! python3 -c \"import PIL\" &> /dev/null; then\n        print_warning \"Pillow not installed, installing...\"\n        pip install Pillow\n    fi\n    \n    # Run generator\n    python3 generate-assets.py\n    print_step \"Assets generated successfully\"\n}\n\nfunction prepare_screenshots() {\n    echo \"Preparing screenshots...\"\n    echo \"\"\n    \n    if [ ! -d \"$SCRIPT_DIR/screenshots/phone\" ]; then\n        print_error \"Screenshots directory not found\"\n        echo \"  Please capture screenshots first and place in: $SCRIPT_DIR/screenshots/phone/\"\n        exit 1\n    fi\n    \n    cd \"$SCRIPT_DIR\"\n    \n    # Check if Python is available\n    if command -v python3 &> /dev/null; then\n        echo \"Adding captions to screenshots...\"\n        python3 add_captions_to_screenshots.py\n        print_step \"Screenshots prepared\"\n    else\n        print_warning \"Python3 not available, skipping caption addition\"\n    fi\n}\n\nfunction build_apk() {\n    echo \"Building production APK...\"\n    echo \"\"\n    \n    cd \"$PROJECT_ROOT\"\n    \n    npm run build:mobile:prod\n    \n    if [ -f \"app-release.apk\" ]; then\n        print_step \"APK built successfully: app-release.apk\"\n    else\n        print_error \"APK build failed\"\n        exit 1\n    fi\n}\n\nfunction show_status() {\n    echo \"PlayStore Submission Status\"\n    echo \"============================\"\n    echo \"\"\n    \n    # Check assets\n    echo \"📦 Assets:\"\n    if [ -d \"$SCRIPT_DIR/icons\" ] && [ \"$(ls -A $SCRIPT_DIR/icons)\" ]; then\n        print_step \"App icons generated\"\n    else\n        print_warning \"App icons not generated\"\n    fi\n    \n    if [ -d \"$SCRIPT_DIR/graphics\" ] && [ \"$(ls -A $SCRIPT_DIR/graphics)\" ]; then\n        print_step \"Graphics files present\"\n    else\n        print_warning \"Graphics files missing\"\n    fi\n    \n    if [ -d \"$SCRIPT_DIR/screenshots/phone\" ] && [ \"$(ls -A $SCRIPT_DIR/screenshots/phone)\" ]; then\n        local count=$(ls -1 $SCRIPT_DIR/screenshots/phone | wc -l)\n        print_step \"Screenshots: $count files\"\n    else\n        print_warning \"Screenshots not captured\"\n    fi\n    \n    echo \"\"\n    echo \"📝 Metadata:\"\n    if [ -f \"$SCRIPT_DIR/app-listing.json\" ]; then\n        print_step \"App listing configured\"\n    else\n        print_warning \"App listing not configured\"\n    fi\n    \n    echo \"\"\n    echo \"📱 APK:\"\n    if [ -f \"$PROJECT_ROOT/app-release.apk\" ]; then\n        local size=$(du -h \"$PROJECT_ROOT/app-release.apk\" | cut -f1)\n        print_step \"Production APK ready: $size\"\n    else\n        print_warning \"APK not built\"\n    fi\n    \n    echo \"\"\n}\n\nfunction show_help() {\n    cat << EOF\nUsage: $0 [command]\n\nCommands:\n  generate    - Generate all PlayStore assets from logo\n  screenshots - Prepare and caption screenshots\n  build       - Build production APK\n  status      - Show current preparation status\n  help        - Show this help message\n\nExamples:\n  $0 generate        # Generate icons and graphics\n  $0 screenshots     # Add captions to screenshots\n  $0 build           # Build production APK\n  $0 status          # Check what's been prepared\n\nWorkflow:\n  1. $0 generate      # Generate assets\n  2. Capture screenshots from app\n  3. $0 screenshots   # Add captions\n  4. $0 build         # Build APK\n  5. $0 status        # Verify everything\n  6. Upload to PlayStore Console\n\nFor detailed instructions, see:\n  - README.md\n  - PLAYSTORE_DEPLOYMENT_GUIDE.md\n  - SCREENSHOTS_GUIDE.md\nEOF\n}\n\n# Main\ncase \"${1:-help}\" in\n    generate)\n        generate_assets\n        ;;\n    screenshots)\n        prepare_screenshots\n        ;;\n    build)\n        build_apk\n        ;;\n    status)\n        show_status\n        ;;\n    help)\n        show_help\n        ;;\n    *)\n        print_error \"Unknown command: $1\"\n        echo \"\"\n        show_help\n        exit 1\n        ;;\nesac\n\necho \"\"\necho \"Done! ✨\"\n